questoes.codigoInicial:
export default async function ListaUsuarios() {
  const res = await fetch('https://jsonplaceholder.typicode.com/users');
  const usuarios = await res.json();

  return <ul>
    {usuarios.map(u => <li key={u.id}>{u.name}</li>)}
  </ul>;
}

